export const faqHtml = "<div class=\"page-wrap\">\n\n  <div class=\"page-header\">\n    <div class=\"page-eyebrow\">Help centre</div>\n    <h1 class=\"page-title\">How can we help?</h1>\n    <p class=\"page-subtitle\">Everything about ordering, shipping, returns, and our products. Find your answer here before you reach out.</p>\n  </div>\n\n  <div class=\"trust-bar\" aria-label=\"Quick facts\">\n    <div class=\"trust-item\">\n      <div class=\"trust-num\">12-24h</div>\n      <div class=\"trust-label\">Email reply time</div>\n    </div>\n    <div class=\"trust-item\">\n      <div class=\"trust-num\">30-day</div>\n      <div class=\"trust-label\">Money-back guarantee</div>\n    </div>\n    <div class=\"trust-item\">\n      <div class=\"trust-num\">Free</div>\n      <div class=\"trust-label\">Return labels, on us</div>\n    </div>\n    <div class=\"trust-item\">\n      <div class=\"trust-num\">100%</div>\n      <div class=\"trust-label\">Orders fully tracked</div>\n    </div>\n  </div>\n\n  <div class=\"search-wrap\">\n    <span class=\"search-icon\" aria-hidden=\"true\">\n      <svg viewBox=\"0 0 24 24\" width=\"18\" height=\"18\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><circle cx=\"11\" cy=\"11\" r=\"8\"/><path d=\"m21 21-4.35-4.35\"/></svg>\n    </span>\n    <input class=\"search-input\" id=\"faq-search\" type=\"search\" placeholder=\"Search questions, e.g. tracking, return, size...\" autocomplete=\"off\" aria-label=\"Search FAQ\">\n    <button class=\"search-clear\" id=\"search-clear\" aria-label=\"Clear search\" onclick=\"clearSearch()\">×</button>\n  </div>\n\n  <div class=\"faq-layout\">\n\n    <aside class=\"section-nav\" aria-label=\"FAQ sections\">\n      <div class=\"section-nav-label\">Sections</div>\n      <ul>\n        <li><a href=\"#about\" class=\"nav-link active\">About MUSE <span class=\"section-nav-count\">7</span></a></li>\n        <li><a href=\"#sizing\" class=\"nav-link\">Sizing <span class=\"section-nav-count\">4</span></a></li>\n        <li><a href=\"#ordering\" class=\"nav-link\">Ordering <span class=\"section-nav-count\">7</span></a></li>\n        <li><a href=\"#pricing\" class=\"nav-link\">Pricing <span class=\"section-nav-count\">4</span></a></li>\n        <li><a href=\"#shipping\" class=\"nav-link\">Shipping <span class=\"section-nav-count\">7</span></a></li>\n        <li><a href=\"#tracking\" class=\"nav-link\">Tracking <span class=\"section-nav-count\">5</span></a></li>\n        <li><a href=\"#returns\" class=\"nav-link\">Returns <span class=\"section-nav-count\">7</span></a></li>\n        <li><a href=\"#account\" class=\"nav-link\">Account <span class=\"section-nav-count\">3</span></a></li>\n        <li><a href=\"#contact\" class=\"nav-link\">Contact <span class=\"section-nav-count\">4</span></a></li>\n        <li><a href=\"#legal\" class=\"nav-link\">Legal <span class=\"section-nav-count\">5</span></a></li>\n      </ul>\n      <div class=\"contact-nav-card\">\n        <h4>Still stuck?</h4>\n        <p>Our team replies within 12-24 hours.</p>\n        <a href=\"mailto:support@musenz.com\" class=\"contact-nav-btn\">Email us</a>\n      </div>\n    </aside>\n\n    <main>\n      <div class=\"faq-sections\" id=\"faq-sections\">\n\n        <div class=\"no-results\" id=\"no-results\">\n          <div class=\"no-results-title\">No results found</div>\n          <p>Try different words, or <a href=\"mailto:support@musenz.com\" style=\"color:var(--orange);text-decoration:underline\">email us</a> and we'll get back to you within 12-24 hours.</p>\n        </div>\n\n        <!-- SECTION 1: ABOUT -->\n        <div class=\"faq-section\" id=\"about\" data-section=\"about\">\n          <div class=\"section-head\" onclick=\"toggleSection(this)\" role=\"button\" aria-expanded=\"true\" tabindex=\"0\">\n            <div class=\"section-icon\" aria-hidden=\"true\">🏷️</div>\n            <div class=\"section-head-text\">\n              <div class=\"section-head-title\">About MUSE NZ and Our Products</div>\n              <div class=\"section-head-sub\">UA explained, quality, boxes, and where we are based</div>\n            </div>\n            <span class=\"section-chevron\" aria-hidden=\"true\">⌄</span>\n          </div>\n          <div class=\"section-body\">\n\n            <div class=\"faq-item\" data-q=\"what is muse nz who are you about\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">What is MUSE NZ?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>MUSE NZ is an Auckland-based online store focused on premium footwear and outerwear. We source products from verified overseas manufacturing partners, check every item at our Auckland workspace, and ship across New Zealand via NZ Post.</p>\n                <p>Our goal is simple: give New Zealanders access to the styles they want at prices that reflect how the products are actually made, not what a licensed retail chain needs to charge.</p>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"authentic ua unauthorized authentic real legit products genuine\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">Are your products authentic? What does \"UA\" mean?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>All our products are <strong>Unauthorized Authentic (UA)</strong>. Here is what that actually means in plain terms:</p>\n                <div class=\"answer-box\">\n                  <strong>What UA is:</strong> Products made with the same materials, the same construction methods, and in many cases the same factories as the official retail versions. The only difference is they are produced without brand authorisation or licensing agreements.\n                </div>\n                <div class=\"answer-box\">\n                  <strong>What UA is not:</strong> Cheap knockoffs with low-grade materials. UA products are built to the same standard as retail. We check every item before it ships.\n                </div>\n                <div class=\"answer-box good\">\n                  <strong>Why the price is lower:</strong> Retail pricing includes brand licensing fees, retailer margins, regional distribution costs, and advertising. None of that exists in the UA supply chain. You pay for the product, not the corporate structure around it.\n                </div>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"same quality retail official store compare\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">Are your products the same quality as what I'd buy in a retail store?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>Yes. UA products are made to the same spec as the retail version. Same materials, same sole construction, same stitching. The price difference is structural, not a quality compromise. You get the same product without the licensed retail premium built into the cost.</p>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"box come with box original accessories packaging included\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">Do products come with a box?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>Yes. All products come with a box. Standard accessories like laces and dust bags are included where applicable.</p>\n                <div class=\"answer-box warn\">\n                  <strong>Important:</strong> The box is part of the item. If you want to return or exchange, the box must be in brand-new condition. Crushed, written on, or damaged boxes are not accepted. Official brand receipts or retail authentication tags are not included, as our products do not come through official retail channels.\n                </div>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"where are you based auckland new zealand location nz business\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">Where are you based?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>We are based in <strong>Auckland, New Zealand</strong>. Our NZ Stock items are held at our Auckland workspace and dispatched from there. Our support team is also Auckland-based. You can reach us at <a href=\"mailto:support@musenz.com\">support@musenz.com</a> or on Instagram <a href=\"https://instagram.com/muse.nz\" target=\"_blank\" rel=\"noreferrer\">@muse.nz</a>.</p>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"product photos images real iphone actual photography edited polished stock what you see\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">Are your product photos the actual items?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>Yes. Every photo on our website is taken by us, on an iPhone, of the actual product. No studio lighting rigs, no editing software, no stock imagery, no renders. You are looking at real goods photographed in real conditions.</p>\n                <p>We do this deliberately. We want you to see exactly what arrives at your door before you buy it. The colour, the materials, the box, the tags. What you see on the page is what you get.</p>\n                <div class=\"answer-box good\">If a photo ever looks off or you want to see a specific angle before buying, message us on Instagram <a href=\"https://instagram.com/muse.nz\" target=\"_blank\" rel=\"noreferrer\">@muse.nz</a> and we will send you more shots.</div>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"legitimate legit trust safe scam real trustworthy\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">How do I know MUSE NZ is a legitimate store?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>Fair question. Here is what you can check:</p>\n                <ul>\n                  <li>Auckland-based NZ business, operating under NZ law</li>\n                  <li>Active support email at support@musenz.com, replied to within 12-24 hours</li>\n                  <li>Verified customer reviews on our website and Instagram</li>\n                  <li>All payments go through Stripe, a globally trusted payment processor. We never store your card details</li>\n                  <li>Every order is fully tracked via NZ Post. You get a tracking number with every dispatch</li>\n                  <li>30-day money-back guarantee. If something is wrong, we sort it out</li>\n                </ul>\n              </div>\n            </div>\n\n          </div>\n        </div>\n\n        <!-- SECTION 2: SIZING -->\n        <div class=\"faq-section\" id=\"sizing\" data-section=\"sizing\">\n          <div class=\"section-head\" onclick=\"toggleSection(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n            <div class=\"section-icon\" aria-hidden=\"true\">📏</div>\n            <div class=\"section-head-text\">\n              <div class=\"section-head-title\">Sizing and Fit</div>\n              <div class=\"section-head-sub\">Brand sizing differences, EU vs US, and where to find size charts</div>\n            </div>\n            <span class=\"section-chevron\" aria-hidden=\"true\">⌄</span>\n          </div>\n          <div class=\"section-body\">\n\n            <div class=\"faq-item\" data-q=\"what size should I order sizing guide how to find size eu us birkenstock new balance\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">How do I find my size?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>Sizing varies between brands, so there is no single rule that covers everything. The best place to check is <strong>the product page for the style you want</strong>. Every product page has a size chart for that brand, plus a fit note based on what previous buyers have said.</p>\n                <p>A few things worth knowing about some of our brands:</p>\n                <ul>\n                  <li><strong>New Balance:</strong> Listed in EU sizing on our site. They tend to fit a bit smaller for most people due to the inside padding. Reference your usual size in the chart on the product page.</li>\n                  <li><strong>Birkenstock:</strong> EU sizing. Most people need to go down one size from their standard US size.</li>\n                  <li><strong>Nike / Jordan:</strong> US sizing. Some silhouettes run narrow, so certain styles may suit going up half a size.</li>\n                  <li><strong>UGG / Stussy:</strong> US sizing. Generally true to size.</li>\n                </ul>\n                <p>When in doubt, email us at <a href=\"mailto:support@musenz.com\">support@musenz.com</a> with your usual shoe size and the style you are looking at. We will point you in the right direction.</p>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"run true to size small large fit\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">Do sneakers run true to size?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>It depends on the brand. There is no one-size-fits-all answer. Each product page has a specific fit note based on buyer reviews, telling you whether that style runs small, large, or true to size. Have a look at the page for the item you are after and the note will be right next to the size selector.</p>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"size not available sold out out of stock restock notify\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">What if the size I want is not available?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>If your size is not showing, it is either out of stock or sold out for that drop. Here is what to do:</p>\n                <ul>\n                  <li>Follow us on <a href=\"https://instagram.com/muse.nz\" target=\"_blank\" rel=\"noreferrer\">@muse.nz</a> on Instagram. Restocks and new sizes get announced there first</li>\n                  <li>Check back on the website. Popular sizes come back regularly</li>\n                  <li>Email us at <a href=\"mailto:support@musenz.com\">support@musenz.com</a> to ask about restock timing for a specific style and size</li>\n                  <li>Use our <a href=\"#\">Shoe Request form</a> if the model or size is not listed at all</li>\n                </ul>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"request shoe colourway model specific style can you get custom\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">Can I request a specific shoe, colourway, or model?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>Yes. Use our <a href=\"#\">Shoe Request form</a> or email us at <a href=\"mailto:support@musenz.com\">support@musenz.com</a> with the brand, model, colourway, and size. We cannot guarantee it every time, but we do source popular requests and will let you know when we can get it in.</p>\n              </div>\n            </div>\n\n          </div>\n        </div>\n\n        <!-- SECTION 3: ORDERING -->\n        <div class=\"faq-section\" id=\"ordering\" data-section=\"ordering\">\n          <div class=\"section-head\" onclick=\"toggleSection(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n            <div class=\"section-icon\" aria-hidden=\"true\">🛒</div>\n            <div class=\"section-head-text\">\n              <div class=\"section-head-title\">Ordering</div>\n              <div class=\"section-head-sub\">Placing orders, changes, payment, and confirmation emails</div>\n            </div>\n            <span class=\"section-chevron\" aria-hidden=\"true\">⌄</span>\n          </div>\n          <div class=\"section-body\">\n\n            <div class=\"faq-item\" data-q=\"how to place order buy checkout purchase\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">How do I place an order?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>Browse the site, pick your item and size, and add it to your bag. At checkout, enter your delivery address and payment details, then confirm. A confirmation email will land in your inbox within a few minutes. If you do not see it, check your spam folder.</p>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"cancel modify change order after placing wrong size address\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">Can I change or cancel my order after placing it?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>We start processing orders quickly, so time matters here. If you need to change or cancel, email us straight away at <a href=\"mailto:support@musenz.com\">support@musenz.com</a> with your order number and what needs changing. We will do our best, but once an order moves into preparation we may not be able to stop it. If it has already been dispatched, it will need to go through our returns process when it arrives.</p>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"wrong shipping address incorrect address typo mistake\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">I entered the wrong shipping address. What do I do?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>Email us immediately at <a href=\"mailto:support@musenz.com\">support@musenz.com</a> with your order number and the correct address. If the order has not yet dispatched we can update it. If it has already gone out we will try to redirect with NZ Post, though that is not always possible. The sooner you contact us, the better the chance of fixing it.</p>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"no confirmation email not received didn't get check spam\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">I did not receive a confirmation email. What should I do?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>Start by checking your spam or junk folder — that is where these most often end up. Also check that the email address you entered at checkout was correct. If you still cannot find it, email us at <a href=\"mailto:support@musenz.com\">support@musenz.com</a> with your name and when you ordered and we will resend it.</p>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"payment methods accepted visa mastercard apple pay afterpay google pay klarna\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">What payment methods do you accept?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>We accept all the main options:</p>\n                <div class=\"pay-badges\">\n                  <img src=\"/payment-badges/Visa.png\" alt=\"Visa\" class=\"pay-badge-img\">\n                  <img src=\"/payment-badges/mastercard.png\" alt=\"Mastercard\" class=\"pay-badge-img\">\n                  <img src=\"/payment-badges/Amex.png\" alt=\"American Express\" class=\"pay-badge-img\">\n                  <img src=\"/payment-badges/Applepay.png\" alt=\"Apple Pay\" class=\"pay-badge-img\">\n                  <img src=\"/payment-badges/Gpay.png\" alt=\"Google Pay\" class=\"pay-badge-img\">\n                  <img src=\"/payment-badges/Afterpay.png\" alt=\"Afterpay\" class=\"pay-badge-img\">\n                  <img src=\"/payment-badges/Klarna.png\" alt=\"Klarna\" class=\"pay-badge-img\">\n                </div>\n                <p>Payment is taken in full when you order. Afterpay and Klarna split your total into four fortnightly payments. Your first payment goes out at checkout; the rest follow every two weeks, interest-free.</p>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"safe to pay secure checkout payment security card details\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">Is it safe to pay on your website?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>Yes, completely. All payments go through Stripe, one of the world's most trusted payment processors used by millions of businesses. Your card details are encrypted and we never store them on our end. When you pay with Apple Pay or Google Pay, your actual card number is never shared with us at all. Your payment is in safe hands.</p>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"discount code promo coupon promotion sale offer\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">Do you have a discount code?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>We run drop-specific promotions from time to time. Follow us on <a href=\"https://instagram.com/muse.nz\" target=\"_blank\" rel=\"noreferrer\">@muse.nz</a> and sign up to our email list to get them first. We do not have a permanent public code. If you have one, there is a \"Have a code?\" link in the bag that reveals the field at checkout.</p>\n              </div>\n            </div>\n\n          </div>\n        </div>\n\n        <!-- SECTION 4: PRICING -->\n        <div class=\"faq-section\" id=\"pricing\" data-section=\"pricing\">\n          <div class=\"section-head\" onclick=\"toggleSection(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n            <div class=\"section-icon\" aria-hidden=\"true\">💲</div>\n            <div class=\"section-head-text\">\n              <div class=\"section-head-title\">Pricing and Currency</div>\n              <div class=\"section-head-sub\">Currency, GST, why prices are lower, and payment plans</div>\n            </div>\n            <span class=\"section-chevron\" aria-hidden=\"true\">⌄</span>\n          </div>\n          <div class=\"section-body\">\n\n            <div class=\"faq-item\" data-q=\"currency nzd new zealand dollars what currency price\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">What currency are your prices in?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>All prices are listed and charged in <strong>New Zealand Dollars (NZD)</strong>. If you are shopping from outside New Zealand, your bank will convert the charge to your local currency at their exchange rate.</p>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"gst tax included price already included\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">Is GST included in the price?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>Yes. All prices include NZ GST (15%). No extra tax gets added at checkout. What you see is what you pay.</p>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"why lower price cheap affordable retail price difference cheaper\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">Why are your prices so much lower than retail?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>The short answer: we sell UA (Unauthorized Authentic) products sourced directly from overseas manufacturing partners. There are no brand licensing fees, no licensed retailer margins, and no multi-layer distribution costs. All of that is what makes retail prices so high. We cut out the layers. You pay for the product itself, not the supply chain around it.</p>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"afterpay buy now pay later klarna instalment payment plan\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">Can I pay in instalments?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>Yes. Both <strong>Afterpay</strong> and <strong>Klarna</strong> are available at checkout. Your total gets split into four equal fortnightly payments. The first comes out when you confirm your order; the rest follow every two weeks. Interest-free as long as payments are made on time. Standard eligibility terms apply.</p>\n              </div>\n            </div>\n\n          </div>\n        </div>\n\n        <!-- SECTION 5: SHIPPING -->\n        <div class=\"faq-section\" id=\"shipping\" data-section=\"shipping\">\n          <div class=\"section-head\" onclick=\"toggleSection(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n            <div class=\"section-icon\" aria-hidden=\"true\">📦</div>\n            <div class=\"section-head-text\">\n              <div class=\"section-head-title\">Shipping and Delivery</div>\n              <div class=\"section-head-sub\">NZ Stock vs Standard Delivery, timeframes, customs, and lost parcels</div>\n            </div>\n            <span class=\"section-chevron\" aria-hidden=\"true\">⌄</span>\n          </div>\n          <div class=\"section-body\">\n\n            <div class=\"faq-item\" data-q=\"shipping options nz stock standard delivery what options available\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">What shipping options do you offer?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>We have two fulfilment options. Every product page shows which one applies:</p>\n                <div class=\"answer-box\">\n                  <strong>NZ Stock</strong> — physically held at our Auckland workspace. Out the door within 1-3 business days via NZ Post. Best when you need it fast.\n                </div>\n                <div class=\"answer-box\">\n                  <strong>Standard Delivery</strong> — items sourced from our overseas warehouse, shipped to New Zealand, then delivered by NZ Post. Around 13-16 business days total. Fully tracked. This is how we keep prices well below retail.\n                </div>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"how long delivery take days weeks arrive time\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">How long will my order take to arrive?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <ul>\n                  <li><strong>NZ Stock:</strong> 1-3 business days to dispatch, plus standard NZ Post delivery (usually 1-3 days within New Zealand)</li>\n                  <li><strong>Standard Delivery:</strong> Around 13-16 business days from when you order to when it arrives</li>\n                </ul>\n                <p>Business days do not include weekends or NZ public holidays. Your tracking link will always show the latest estimated delivery date.</p>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"international shipping overseas outside new zealand\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">Do you ship internationally?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>We ship within New Zealand only right now. All orders go via NZ Post. We are looking at international shipping for the future. Follow us on <a href=\"https://instagram.com/muse.nz\" target=\"_blank\" rel=\"noreferrer\">@muse.nz</a> for updates.</p>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"how much shipping cost free shipping threshold express standard price\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">How much does shipping cost?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <div class=\"answer-box\">\n                  <strong>Standard shipping (NZ Post Tracked)</strong> — $7 NZD\n                </div>\n                <div class=\"answer-box\">\n                  <strong>Express shipping (NZ Couriers)</strong> — $14 NZD\n                </div>\n                <div class=\"answer-box\">\n                  <strong>Parcel protection</strong> — $4.99 NZD. Covers you for a full replacement or refund if your parcel is confirmed lost in transit. Optional add-on at checkout.\n                </div>\n                <div class=\"answer-box good\"><strong>Free standard shipping on orders over $200 NZD.</strong> Your bag shows how close you are as you add items.</div>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"customs import duties fees taxes nz buyer\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">Will I have to pay customs or import duties?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>No. For New Zealand buyers there are no customs charges or import duties on your MUSE order. We handle the import logistics as part of the Standard Delivery process. The price at checkout is the total. Nothing extra gets charged when it arrives.</p>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"order late delayed taking longer than expected overdue\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">My order is taking longer than expected. What should I do?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>First, check your tracking link for the latest update. Small delays of 1-3 extra business days are normal, especially during busy periods. If your tracking has not moved for more than 7 consecutive business days, or your delivery window has passed by more than 3 business days, get in touch at <a href=\"mailto:support@musenz.com\">support@musenz.com</a> with your order number and we will look into it straight away.</p>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"parcel lost missing gone what happens lost in transit insurance protection\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">What happens if my parcel is lost?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>Email us at <a href=\"mailto:support@musenz.com\">support@musenz.com</a> with your order number and we will investigate with NZ Post on your behalf.</p>\n                <div class=\"answer-box good\">\n                  <strong>If you added parcel protection at checkout:</strong> you are covered for a full replacement or refund if the parcel is confirmed lost. No hassle.\n                </div>\n                <div class=\"answer-box\">\n                  <strong>Without parcel protection:</strong> we will still investigate and do our best to find a resolution, but outcomes depend on what the NZ Post investigation finds. We always advocate for our customers.\n                </div>\n                <p>Once tracking shows a parcel as delivered, we are not able to take responsibility for items that go missing after that point, as delivery to your address has been confirmed by the courier.</p>\n              </div>\n            </div>\n\n          </div>\n        </div>\n\n        <!-- SECTION 6: TRACKING -->\n        <div class=\"faq-section\" id=\"tracking\" data-section=\"tracking\">\n          <div class=\"section-head\" onclick=\"toggleSection(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n            <div class=\"section-icon\" aria-hidden=\"true\">📍</div>\n            <div class=\"section-head-text\">\n              <div class=\"section-head-title\">Tracking Your Order</div>\n              <div class=\"section-head-sub\">Tracking numbers, status meanings, and gaps between updates</div>\n            </div>\n            <span class=\"section-chevron\" aria-hidden=\"true\">⌄</span>\n          </div>\n          <div class=\"section-body\">\n\n            <div class=\"faq-item\" data-q=\"how to track order tracking number where is my order\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">How do I track my order?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>Once your order is dispatched, you will get an email with your tracking number. Enter it on our <a href=\"#\">Tracking page</a> or go directly to the <a href=\"https://www.nzpost.co.nz/tools/tracking\" target=\"_blank\" rel=\"noreferrer\">NZ Post website</a> for live updates.</p>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"haven't received tracking number no tracking email\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">I have not received a tracking number. What should I do?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>Check your spam folder first. Then allow these timeframes before reaching out:</p>\n                <ul>\n                  <li><strong>NZ Stock:</strong> tracking arrives within 1-3 business days of ordering</li>\n                  <li><strong>Standard Delivery:</strong> tracking can take 3-7 business days, as items ship from our overseas warehouse once ready</li>\n                </ul>\n                <p>Still nothing after that? Email us at <a href=\"mailto:support@musenz.com\">support@musenz.com</a> with your order number.</p>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"tracking not updated several days no movement stuck normal\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">My tracking has not updated in a few days. Is that normal?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>Yes, especially for Standard Delivery during the international leg. Tracking scans happen at key handoff points, but there can be 3-6 business day gaps between scans while your parcel is physically moving. This is normal and does not mean your order is lost.</p>\n                <p>If it has been more than 10 business days with no update and your delivery window has passed, get in touch and we will investigate.</p>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"tracking status meaning what does status mean confirmed processing shipped arrived delivered\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">What do the tracking statuses mean?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <ul>\n                  <li><strong>Order Confirmed</strong> — Received and in our system. Confirmation email on its way.</li>\n                  <li><strong>Processing / Quality Check</strong> — Your item is being inspected and packed.</li>\n                  <li><strong>Tracking Generated</strong> — Tracking number created. Parcel preparing to leave the warehouse.</li>\n                  <li><strong>In Transit (International)</strong> — Standard Delivery only. Your parcel is on its way from our overseas warehouse. Usually 5-10 business days for this leg.</li>\n                  <li><strong>Arrived in New Zealand</strong> — Cleared NZ customs and handed to NZ Post.</li>\n                  <li><strong>Out for Delivery</strong> — NZ Post has it and is delivering today.</li>\n                  <li><strong>Delivered</strong> — Delivered to your address.</li>\n                </ul>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"overseas carrier name shows international why different china\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">Why does my tracking show an overseas carrier name?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>Standard Delivery orders travel on an international carrier from our overseas warehouse to New Zealand before being handed to NZ Post. The first leg may show the international carrier's name. Once it arrives in NZ, NZ Post takes over for final delivery. Our <a href=\"#\">Tracking page</a> combines both legs into one view so you can follow the whole journey.</p>\n              </div>\n            </div>\n\n          </div>\n        </div>\n\n        <!-- SECTION 7: RETURNS -->\n        <div class=\"faq-section\" id=\"returns\" data-section=\"returns\">\n          <div class=\"section-head\" onclick=\"toggleSection(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n            <div class=\"section-icon\" aria-hidden=\"true\">🔄</div>\n            <div class=\"section-head-text\">\n              <div class=\"section-head-title\">Returns and Exchanges</div>\n              <div class=\"section-head-sub\">Policy, conditions, how to start a return, and damaged items</div>\n            </div>\n            <span class=\"section-chevron\" aria-hidden=\"true\">⌄</span>\n          </div>\n          <div class=\"section-body\">\n\n            <div class=\"faq-item\" data-q=\"return exchange policy what is returns policy refund\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">What is your return and exchange policy?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>You have <strong>7 business days from receiving your order</strong> to request a return or exchange. Items must meet our condition requirements below.</p>\n                <div class=\"answer-box\"><strong>Size exchange</strong> — we swap for a different size of the same item, subject to stock availability.</div>\n                <div class=\"answer-box\"><strong>Refund</strong> — we refund to your original payment method once the item is received and checked.</div>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"condition item requirements unworn box brand new return eligible\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">What condition does the item need to be in?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>To qualify, items need to tick all of these boxes:</p>\n                <ul>\n                  <li>Brand-new condition with no signs of wear, creasing, dirt, or ground contact</li>\n                  <li>Original box in perfect condition, not crushed, taped, written on, or damaged in any way</li>\n                  <li>All original accessories (laces, dust bags) present</li>\n                </ul>\n                <div class=\"answer-box warn\">Items that have been worn, even briefly indoors, or have a damaged box cannot be returned.</div>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"how to start return exchange process steps initiate\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">How do I start a return or exchange?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>Email <a href=\"mailto:support@musenz.com\">support@musenz.com</a> within 7 business days of receiving your order. Include:</p>\n                <ul>\n                  <li>Your order number</li>\n                  <li>The item you want to return or exchange</li>\n                  <li>Your reason</li>\n                  <li>For exchanges: the size or item you want instead</li>\n                </ul>\n                <div class=\"answer-box warn\">Do not send anything back until we have confirmed your return and sent you a prepaid label.</div>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"how long refund take process time exchange wait overseas stock\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">How long does the return or exchange process take?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>Once we receive and check your returned item, we will confirm the outcome within 1 business day.</p>\n                <p><strong>For refunds:</strong> processed within 3-5 business days back to your original payment method. Your bank may take a few extra days after that to show the credit.</p>\n                <p><strong>For exchanges:</strong> if the size you need is in our NZ Stock, we get it out quickly. If it needs to come from our overseas warehouse, there will be an additional 13-16 business day wait for the new item to arrive in New Zealand before we can send it to you. We will keep you updated on the timeline throughout.</p>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"wrong item received damaged defective incorrect broken\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">I received the wrong item or my item arrived damaged. What do I do?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>Email us straight away at <a href=\"mailto:support@musenz.com\">support@musenz.com</a> with your order number and clear photos of: (1) the item you received, (2) any damage, and (3) the box and packaging as it arrived. Do not wear or use the item. Wrong items and damaged items are always resolved at no cost to you, including the return shipping.</p>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"return shipping cost who pays label prepaid free\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">Do I have to pay for return shipping?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>No. Return labels are on us. Once your return is approved, we will email you a prepaid NZ Post label. Just repack the item, stick the label on, and drop it at any NZ Post shop or outlet. You do not pay anything.</p>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"exchange different style model completely different product\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">Can I exchange for a completely different style?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>Our standard exchange is for a different size of the same item. If you want a completely different product, email us at <a href=\"mailto:support@musenz.com\">support@musenz.com</a> and we will look at it case by case. We will always try to find a workable solution.</p>\n              </div>\n            </div>\n\n          </div>\n        </div>\n\n        <!-- SECTION 8: ACCOUNT -->\n        <div class=\"faq-section\" id=\"account\" data-section=\"account\">\n          <div class=\"section-head\" onclick=\"toggleSection(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n            <div class=\"section-icon\" aria-hidden=\"true\">👤</div>\n            <div class=\"section-head-text\">\n              <div class=\"section-head-title\">Account and Orders</div>\n              <div class=\"section-head-sub\">Guest checkout, order history, and invoices</div>\n            </div>\n            <span class=\"section-chevron\" aria-hidden=\"true\">⌄</span>\n          </div>\n          <div class=\"section-body\">\n\n            <div class=\"faq-item\" data-q=\"need account create guest checkout sign up login\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">Do I need to create an account to order?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>No. Guest checkout works fine. Your confirmation email and tracking will all come through to whatever email you entered at checkout. Creating an account is optional and gives you order history, live tracking in one place, and saved addresses for next time.</p>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"view past orders history previous orders\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">How do I view my past orders?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>If you checked out as a guest, all your order information is in the confirmation email. If you have an account, log in and your full order history is in your dashboard, including live tracking for anything still on its way.</p>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"receipt invoice tax gst business proof of purchase\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">Can I get a receipt or invoice?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>Your order confirmation email is your receipt. It includes a full itemised breakdown with pricing and GST. If you need a separate invoice for business or tax purposes, email us at <a href=\"mailto:support@musenz.com\">support@musenz.com</a> with your order number and we will send one within 1 business day.</p>\n              </div>\n            </div>\n\n          </div>\n        </div>\n\n        <!-- SECTION 9: CONTACT -->\n        <div class=\"faq-section\" id=\"contact\" data-section=\"contact\">\n          <div class=\"section-head\" onclick=\"toggleSection(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n            <div class=\"section-icon\" aria-hidden=\"true\">💬</div>\n            <div class=\"section-head-text\">\n              <div class=\"section-head-title\">Contact and Support</div>\n              <div class=\"section-head-sub\">How to reach us and what to expect</div>\n            </div>\n            <span class=\"section-chevron\" aria-hidden=\"true\">⌄</span>\n          </div>\n          <div class=\"section-body\">\n\n            <div class=\"faq-item\" data-q=\"how to contact muse nz get in touch support email instagram\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">How do I contact MUSE NZ?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <ul>\n                  <li><strong>Email:</strong> <a href=\"mailto:support@musenz.com\">support@musenz.com</a> — best for anything involving your order</li>\n                  <li><strong>Instagram:</strong> <a href=\"https://instagram.com/muse.nz\" target=\"_blank\" rel=\"noreferrer\">@muse.nz</a> — good for general questions and product requests</li>\n                  <li><strong>Facebook:</strong> <a href=\"https://facebook.com/muse.nz.2025\" target=\"_blank\" rel=\"noreferrer\">facebook.com/muse.nz.2025</a></li>\n                </ul>\n                <p>For anything order-related, email is always fastest as it lets us look up your order directly.</p>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"how quickly reply response time how long wait reply time\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">How quickly will you reply?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>We aim to reply to all emails within <strong>12-24 hours, Monday to Friday</strong>. On weekends and NZ public holidays responses may take a bit longer, but we check messages regularly and reply on the next business day.</p>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"emailed no reply haven't heard back follow up\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">I emailed but have not heard back. What should I do?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>If it has been more than 24 hours (not counting weekends and public holidays), check that your email went to <a href=\"mailto:support@musenz.com\">support@musenz.com</a> and have a look in your sent folder to make sure it went through. You are welcome to send a short follow-up. You can also message us on Instagram <a href=\"https://instagram.com/muse.nz\" target=\"_blank\" rel=\"noreferrer\">@muse.nz</a> and we will look into it.</p>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"support hours open when available live chat times\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">What are your support hours?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>We are active <strong>Monday to Friday, NZ business hours (9am to 6pm NZST)</strong>. We check messages outside those hours but send official replies during business hours. We do not have live chat at the moment.</p>\n              </div>\n            </div>\n\n          </div>\n        </div>\n\n        <!-- SECTION 10: LEGAL -->\n        <div class=\"faq-section\" id=\"legal\" data-section=\"legal\">\n          <div class=\"section-head\" onclick=\"toggleSection(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n            <div class=\"section-icon\" aria-hidden=\"true\">🔒</div>\n            <div class=\"section-head-text\">\n              <div class=\"section-head-title\">Privacy, Legal, and Your Data</div>\n              <div class=\"section-head-sub\">Data use, your NZ consumer rights, Terms of Service</div>\n            </div>\n            <span class=\"section-chevron\" aria-hidden=\"true\">⌄</span>\n          </div>\n          <div class=\"section-body\">\n\n            <div class=\"faq-item\" data-q=\"personal information safe data secure privacy\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">Is my personal information safe with MUSE NZ?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>Yes. We only collect what we need to process your order. Your payment information goes through Stripe and we never store it on our end. We do not sell your data to anyone. Full details are in our <a href=\"privacy\">Privacy Policy</a>.</p>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"what data collected how used marketing email\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">What data do you collect and what is it used for?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>We collect your name, email address, shipping address, and order information. We use it to process and fulfil your order, send you order and tracking updates, and respond to support messages. If you have opted in, we also send marketing emails. You can unsubscribe at any time from any email we send.</p>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"consumer guarantees act nz rights refund faulty legal rights\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">What are my rights under the Consumer Guarantees Act (NZ)?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>We operate under New Zealand law, including the <strong>Consumer Guarantees Act 1993</strong> and the <strong>Fair Trading Act 1986</strong>. Under the CGA, you are entitled to a remedy (repair, replacement, or refund) if a product is faulty, does not match its description, or is not fit for purpose. Our returns policy works within your statutory rights. Your legal rights under NZ law are not limited or excluded by anything in our policy.</p>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"delete data privacy request removal gdpr nz privacy act\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">How do I request deletion of my personal data?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>Email <a href=\"mailto:support@musenz.com\">support@musenz.com</a> with the subject line <strong>\"Data Deletion Request\"</strong> and include the email address linked to your account. We will process it within 14 business days under the NZ Privacy Act 2020. Some transactional records may need to be kept for tax compliance reasons even after a deletion request.</p>\n              </div>\n            </div>\n\n            <div class=\"faq-item\" data-q=\"terms of service privacy policy where find legal documents\">\n              <div class=\"faq-q\" onclick=\"toggleItem(this)\" role=\"button\" aria-expanded=\"false\" tabindex=\"0\">\n                <span class=\"faq-q-text\">Where can I find the full Terms of Service and Privacy Policy?</span>\n                <span class=\"faq-chevron\" aria-hidden=\"true\">⌄</span>\n              </div>\n              <div class=\"faq-a\">\n                <p>Both are linked in the footer of every page. Both are governed by New Zealand law.</p>\n                <div style=\"display:flex;gap:10px;margin-top:12px;flex-wrap:wrap;\">\n                  <a href=\"terms\" class=\"answer-pill\">Terms of Service</a>\n                  <a href=\"privacy\" class=\"answer-pill\">Privacy Policy</a>\n                </div>\n              </div>\n            </div>\n\n          </div>\n        </div>\n\n      </div>\n\n      <!-- BOTTOM CTA -->\n      <div class=\"bottom-cta\">\n        <div class=\"bottom-cta-text\">\n          <div class=\"bottom-cta-eyebrow\">Still have a question?</div>\n          <div class=\"bottom-cta-title\">We will sort it out.</div>\n          <div class=\"bottom-cta-sub\">Email us at support@musenz.com. We reply within 12-24 hours.</div>\n        </div>\n        <div class=\"bottom-cta-actions\">\n          <a href=\"mailto:support@musenz.com\" class=\"cta-btn-primary\">\n            <svg viewBox=\"0 0 24 24\" width=\"16\" height=\"16\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M4 4h16c1.1 0 2 .9 2 2v12c0 1.1-.9 2-2 2H4c-1.1 0-2-.9-2-2V6c0-1.1.9-2 2-2z\"/><polyline points=\"22,6 12,13 2,6\"/></svg>\n            Email support\n          </a>\n          <a href=\"https://instagram.com/muse.nz\" target=\"_blank\" rel=\"noreferrer\" class=\"cta-btn-social\">\n            <img src=\"/payment-badges/1x/Asset 2-8.png\" alt=\"\" class=\"social-logo\">\n            Message us on Instagram\n          </a>\n          <a href=\"https://facebook.com/muse.nz.2025\" target=\"_blank\" rel=\"noreferrer\" class=\"cta-btn-social\">\n            <img src=\"/payment-badges/1x/Asset 1-8.png\" alt=\"\" class=\"social-logo\">\n            Facebook\n          </a>\n        </div>\n      </div>\n\n    </main>\n  </div>\n\n</div>"
